# Helper function for subprocess with retry and logging
def run_with_retry_and_log(cmd: list, cwd: str, timeout: int, max_retries: int = 2, job_name: str = "Job"):
    for attempt in range(1, max_retries + 1):
        logger.info(f"[{job_name}] Attempt {attempt}/{max_retries}...")
        try:
            # Dùng subprocess.Popen để log ra màn hình realtime tránh ảo giác treo máy
            process = subprocess.Popen(cmd, cwd=cwd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, encoding='utf-8', errors='replace')

            output_log = []
            for line in iter(process.stdout.readline, ''):
                if line:
                    clean_line = line.rstrip()
                    if clean_line:
                        logger.info(f"[{job_name} LIVE] {clean_line}")
                    output_log.append(clean_line)

            process.stdout.close()
            return_code = process.wait(timeout=timeout)

            if return_code == 0:
                logger.info(f"[{job_name}] Attempt {attempt} successful.")
                return True, ""
            else:
                err_text = "\n".join(output_log)
                err_snippet = err_text[-1000:] if len(err_text) > 1000 else err_text
                logger.warning(f"[{job_name}] Attempt {attempt} failed with code {return_code}.\nSnippet: {err_snippet[-200:]}")
                if attempt == max_retries:
                    return False, err_snippet
                logger.info(f"[{job_name}] Waiting 30s before retry...")
                time.sleep(30)
        except subprocess.TimeoutExpired:
            process.kill()
            logger.error(f"[{job_name}] Attempt {attempt} timed out (> {timeout}s).")
            if attempt == max_retries:
                return False, "TIMEOUT_EXPIRED"
            time.sleep(10)
        except Exception as e:
            logger.error(f"[{job_name}] Attempt {attempt} crash: {e}")
            if attempt == max_retries:
                return False, str(e)
            time.sleep(10)
    return False, "UNKNOWN_ERROR"
